"""
Parameterized generator for GH36_prisma_29274.

Source PR:    https://github.com/prisma/prisma/pull/29274
Source Issue: https://github.com/prisma/prisma/issues/28890

Seed varies: renames 'aggregate' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH36_prisma_29274'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH36_prisma_29274'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('aggregate', 'aggregate' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH36_prisma_29274',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'prisma/prisma',
                "pr_number": 29274,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/prisma/prisma/pull/29274",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'packages/adapter-better-sqlite3/src/conversion.ts': "import { ArgType, ColumnType, ColumnTypeEnum, Debug, ResultValue } from '@prisma/driver-adapter-utils'\n\nimport { PrismaBetterSqlite3Options } from './better-sqlite3'\n\nconst debug = Debug('prisma:driver-adapter:better-sqlite3:conversion')\n\ntype Value = null | string | number | bigint | Buffer\nexport type Row = {\n  /** Number of columns in this row.\n   *\n   * All rows in one {@link ResultSet} have the same number and names of columns.\n   */\n  length: number\n  /** Columns can be accessed like an array by numeric indexes. */\n  [index: number]: Value\n}\n\n// Mirrors sqlite/conversion.rs in quaint\nfunction mapDeclType(declType: string | null): ColumnType | null {\n  if (declType === null) {\n    return null\n  }\n\n  switch (declType.toUpperCase()) {\n    case '':\n      return null\n    case 'DECIMAL':\n      return ColumnTypeEnum.Numeric\n    case 'FLOAT':\n      return ColumnTypeEnum.Float\n    case 'DOUBLE':\n    case 'DOUBLE PRECISION':\n    case 'NUMERIC':\n    case 'REAL':\n      return ColumnTypeEnum.Double\n    case 'TINYINT':\n    case 'SMALLINT':\n    case 'MEDIUMINT':\n    case 'INT':\n    case 'INTEGER':\n    case 'SERIAL':\n    case 'INT2':\n      return ColumnTypeEnum.Int32\n    case 'BIGINT':\n    case 'UNSIGNED BIG INT':\n    case 'INT8':\n      return ColumnTypeEnum.Int64\n    case 'DATETIME':\n    case 'TIMESTAMP':\n      return ColumnTypeEnum.DateTime\n    case 'TIME':\n      return ColumnTypeEnum.Time\n    case 'DATE':\n      return ColumnTypeEnum.Date\n    case 'TEXT':\n    case 'CLOB':\n    case 'CHARACTER':\n    case 'VARCHAR':\n    case 'VARYING CHARACTER':\n    case 'NCHAR':\n    case 'NATIVE CHARACTER':\n    case 'NVARCHAR':\n      return ColumnTypeEnum.Text\n    case 'BLOB':\n      return ColumnTypeEnum.Bytes\n    case 'BOOLEAN':\n      return ColumnTypeEnum.Boolean\n    case 'JSONB':\n      return ColumnTypeEnum.Json\n    default:\n      debug('unknown decltype:', declType)\n      return null\n  }\n}\n\nfunction mapDeclaredColumnTypes(\n  columnTypes: Array<string | null>,\n): [out: Array<ColumnType | null>, empty: Set<number>] {\n  const emptyIndices = new Set<number>()\n  const result = columnTypes.map((typeName, index) => {\n    const mappedType = mapDeclType(typeName)\n    if (mappedType === null) {\n      emptyIndices.add(index)\n    }\n    return mappedType\n  })\n  return [result, emptyIndices]\n}\n\nexport function getColumnTypes(declaredTypes: Array<string | null>, rows: Row[]): ColumnType[] {\n  const [columnTypes, emptyIndices] = mapDeclaredColumnTypes(declaredTypes)\n\n  if (emptyIndices.size === 0) {\n    return columnTypes as ColumnType[]\n  }\n\n  columnLoop: for (const columnIndex of emptyIndices) {\n    // No declared column type in db schema, infer using first non-null value\n    for (let rowIndex = 0; rowIndex < rows.length; rowIndex++) {\n      const candidateValue = rows[rowIndex][columnIndex]\n      if (candidateValue !== null) {\n        columnTypes[columnIndex] = inferColumnType(candidateValue)\n        continue columnLoop\n      }\n    }\n\n    // No non-null value found for this column, fall back to int32 to mimic what quaint does\n    columnTypes[columnIndex] = ColumnTypeEnum.Int32\n  }\n\n  return columnTypes as ColumnType[]\n}\n\nfunction inferColumnType(value: NonNullable<Value>): ColumnType {\n  switch (typeof value) {\n    case 'string':\n      return ColumnTypeEnum.Text\n    case 'bigint':\n      return ColumnTypeEnum.Int64\n    case 'boolean':\n      return ColumnTypeEnum.Boolean\n    case 'number':\n      return ColumnTypeEnum.UnknownNumber\n    case 'object':\n      return inferObjectType(value)\n    default:\n      throw new UnexpectedTypeError(value)\n  }\n}\n\nfunction inferObjectType(value: {}): ColumnType {\n  if (value instanceof ArrayBuffer) {\n    return ColumnTypeEnum.Bytes\n  }\n  throw new UnexpectedTypeError(value)\n}\n\nclass UnexpectedTypeError extends Error {\n  name = 'UnexpectedTypeError'\n  constructor(value: unknown) {\n    const type = typeof value\n    const repr = type === 'object' ? JSON.stringify(value) : String(value)\n    super(`unexpected value of type ${type}: ${repr}`)\n  }\n}\n\nexport function mapRow(row: Row, columnTypes: ColumnType[]): ResultValue[] {\n  const result: ResultValue[] = []\n\n  for (let i = 0; i < row.length; i++) {\n    const value = row[i]\n\n    // If an integer is required and the current number isn't one,\n    // discard the fractional part.\n    if (\n      typeof value === 'number' &&\n      (columnTypes[i] === ColumnTypeEnum.Int32 || columnTypes[i] === ColumnTypeEnum.Int64) &&\n      !Number.isInteger(value)\n    ) {\n      result[i] = Math.trunc(value)\n      continue\n    }\n\n    // Decode DateTime values saved as numeric timestamps which is the\n    // format used by the native quaint sqlite connector.\n    if (['number', 'bigint'].includes(typeof value) && columnTypes[i] === ColumnTypeEnum.DateTime) {\n      result[i] = new Date(Number(value)).toISOString()\n      continue\n    }\n\n    // Convert bigint to string as we can only use JSON-encodable types here.\n    if (typeof value === 'bigint') {\n      result[i] = value.toString()\n      continue\n    }\n\n    result[i] = value\n  }\n\n  return result\n}\n\nexport function mapArg<A>(\n  arg: A | Date,\n  argType: ArgType,\n  options?: PrismaBetterSqlite3Options,\n): null | number | BigInt | Uint8Array | string | A {\n  if (arg === null) {\n    return null\n  }\n\n  if (typeof arg === 'string' && argType.scalarType === 'int') {\n    return Number.parseInt(arg)\n  }\n\n  if (typeof arg === 'string' && argType.scalarType === 'float') {\n    return Number.parseFloat(arg)\n  }\n\n  if (typeof arg === 'string' && argType.scalarType === 'decimal') {\n    // This can lose precision, but SQLite does not have a native decimal type.\n    // This is how we have historically handled it.\n    return Number.parseFloat(arg)\n  }\n\n  if (typeof arg === 'string' && argType.scalarType === 'bigint') {\n    return BigInt(arg)\n  }\n\n  if (typeof arg === 'boolean') {\n    return arg ? 1 : 0 // SQLite does not natively support booleans\n  }\n\n  if (typeof arg === 'string' && argType.scalarType === 'datetime') {\n    arg = new Date(arg)\n  }\n\n  if (arg instanceof Date) {\n    const format = options?.timestampFormat ?? 'iso8601'\n    switch (format) {\n      case 'unixepoch-ms':\n        return arg.getTime()\n      case 'iso8601':\n        return arg.toISOString().replace('Z', '+00:00')\n      default:\n        throw new Error(`Unknown timestamp format: ${format}`)\n    }\n  }\n\n  if (typeof arg === 'string' && argType.scalarType === 'bytes') {\n    return Buffer.from(arg, 'base64')\n  }\n\n  return arg\n}\n",
            'packages/client/tests/functional/unixepoch-ms-datetime/tests.ts': "import { PrismaBetterSqlite3 } from '@prisma/adapter-better-sqlite3'\nimport { PrismaLibSql } from '@prisma/adapter-libsql'\nimport { randomUUID } from 'crypto'\n\nimport { AdapterProviders } from '../_utils/providers'\nimport { DatasourceInfo } from '../_utils/setupTestSuiteEnv'\nimport { NewPrismaClient } from '../_utils/types'\n// @ts-ignore\nimport testMatrix from './_matrix'\nimport type * as imports from './generated/prisma/client'\n\ndeclare const newPrismaClient: NewPrismaClient<imports.PrismaClient, typeof imports.PrismaClient>\n\ntestMatrix.setupTestSuite(\n  ({ driverAdapter }, _suiteMeta, _clientMeta, _cliMeta, info) => {\n    test('can retrieve a unixepoch-ms date time with a find unique query', async () => {\n      const prisma = createClient(info, driverAdapter)\n\n      const created = await prisma.event.create({ data: { name: 'event' } })\n      expect(created).toMatchObject({ createdAt: expect.any(Date) })\n\n      const found = await prisma.event.findUnique({\n        where: {\n          uuid_createdAt: {\n            uuid: created.uuid,\n            createdAt: created.createdAt,\n          },\n        },\n      })\n      expect(found).toMatchObject(created)\n    })\n\n    test('can retrieve a unixepoch-ms date time with a find unique query when it was stored directly as a millis number', async () => {\n      const prisma = createClient(info, driverAdapter)\n\n      const uuid = randomUUID()\n      const now = new Date()\n      await prisma.$executeRaw`INSERT INTO Event (name, uuid, createdAt) VALUES ('event', ${uuid}, ${now.getTime()})`\n\n      const found = await prisma.event.findUnique({\n        where: {\n          uuid_createdAt: {\n            uuid,\n            createdAt: now,\n          },\n        },\n      })\n      expect(found).toMatchObject({ createdAt: now })\n    })\n\n    test('can retrieve a unixepoch-ms date time with a raw query', async () => {\n      const prisma = createClient(info, driverAdapter)\n\n      const created = await prisma.event.create({ data: { name: 'event' } })\n      expect(created).toMatchObject({ createdAt: expect.any(Date) })\n\n      const [event] = (await prisma.$queryRaw`SELECT * FROM Event WHERE createdAt = ${created.createdAt}`) as unknown[]\n      expect(event).toMatchObject(created)\n    })\n\n    test('can retrieve a unixepoch-ms date time with a raw query by a millis number', async () => {\n      const prisma = createClient(info, driverAdapter)\n\n      const created = await prisma.event.create({ data: { name: 'event' } })\n      expect(created).toMatchObject({ createdAt: expect.any(Date) })\n\n      const [event] =\n        (await prisma.$queryRaw`SELECT * FROM Event WHERE createdAt = ${created.createdAt.getTime()}`) as unknown[]\n      expect(event).toMatchObject(created)\n    })\n\n    test('can retrieve a unixepoch-ms date time with a find many query', async () => {\n      const prisma = createClient(info, driverAdapter)\n\n      const created = await prisma.event.create({ data: { name: 'event' } })\n      expect(created).toMatchObject({\n        createdAt: expect.any(Date),\n      })\n\n      const found = await prisma.event.findMany({\n        where: {\n          uuid: created.uuid,\n          createdAt: created.createdAt,\n        },\n      })\n      expect(found).toEqual([created])\n    })\n\n    test('can retrieve a unixepoch-ms date time with compactable find unique queries', async () => {\n      const prisma = createClient(info, driverAdapter)\n\n      const created = await prisma.event.create({ data: { name: 'event' } })\n      expect(created).toMatchObject({\n        createdAt: expect.any(Date),\n      })\n\n      const find = () =>\n        prisma.event.findUnique({\n          where: {\n            uuid_createdAt: {\n              uuid: created.uuid,\n              createdAt: created.createdAt,\n            },\n          },\n        })\n\n      // These two queries are going to be compacted together and run as one.\n      await expect(Promise.all([find(), find()])).resolves.toMatchObject([created, created])\n    })\n  },\n  {\n    optOut: {\n      from: ['sqlserver', 'mysql', 'postgresql', 'cockroachdb', 'mongodb'],\n      reason: 'testing sqlite-specific timestamp behavior',\n    },\n    skipDriverAdapter: {\n      from: ['js_d1'],\n      reason: 'D1 does not need to support the QE unixepoch-ms format',\n    },\n    skipDefaultClientInstance: true,\n    skip: (skip, options) => skip(options.driverAdapter === undefined, 'testing only driver adapters'),\n  },\n)\n\nfunction createClient(info: DatasourceInfo, driverAdapter?: `${AdapterProviders}`) {\n  const constructor = driverAdapter === AdapterProviders.JS_BETTER_SQLITE3 ? PrismaBetterSqlite3 : PrismaLibSql\n\n  return newPrismaClient({\n    // @ts-test-if: driverAdapter !== undefined\n    adapter: new constructor(\n      {\n        url: info.databaseUrl,\n      },\n      {\n        timestampFormat: 'unixepoch-ms',\n      },\n    ),\n  })\n}\n",
        }
